-- GAMES
SELECT 'Финал Кубка Zakovat 2025', id, 'Открытый Кубок Zakovat 2025', '2025-03-15', '2025', 'Финал', 'Завершён', '["МЕГАС", "КОГИТАРЕ", "НЕЙРАЛИНК", "БИГБИКЛАБ"]'
FROM tournaments WHERE title = 'Открытый Кубок Zakovat 2025';

SELECT 'Полуфинал Школьной лиги', id, 'Школьная лига — Весна 2025', '2025-04-20', '2025', 'Полуфинал', 'Завершён', '["ЦЕЗАРЬ", "НЕСТЕРОВ", "БИСМАРК", "НСЖЛ"]'
FROM tournaments WHERE title = 'Школьная лига — Весна 2025';

SELECT 'Финал Брейн-ринга', id, 'Брейн-ринг: Финал сезона', '2025-05-10', '2025', 'Финал', 'Завершён', '["НЕЙРАЛИНК", "МЕГАС", "КОГИТАРЕ"]'
FROM tournaments WHERE title = 'Брейн-ринг: Финал сезона';

-- GAME RESULTS (after games and teams exist)
SELECT g.id, t.id, te.id, 'МЕГАС', '2025-03-15', '2025', 'Zakovat', 'Премьер-лига', 1, 1, 0, 0, 0, 45
FROM games g, tournaments t, teams te WHERE g.title = 'Финал Кубка Zakovat 2025' AND t.title = 'Открытый Кубок Zakovat 2025' AND te.name = 'МЕГАС';

SELECT g.id, t.id, te.id, 'КОГИТАРЕ', '2025-03-15', '2025', 'Zakovat', 'Премьер-лига', 2, 0, 1, 0, 0, 42
FROM games g, tournaments t, teams te WHERE g.title = 'Финал Кубка Zakovat 2025' AND t.title = 'Открытый Кубок Zakovat 2025' AND te.name = 'КОГИТАРЕ';

SELECT g.id, t.id, te.id, 'НЕЙРАЛИНК', '2025-03-15', '2025', 'Zakovat', 'Премьер-лига', 3, 0, 0, 1, 0, 38
FROM games g, tournaments t, teams te WHERE g.title = 'Финал Кубка Zakovat 2025' AND t.title = 'Открытый Кубок Zakovat 2025' AND te.name = 'НЕЙРАЛИНК';

